#n8n #Automation #WorkflowAutomation #GitHub #Projects #DataEngineering
`,

  summary_content: `# Workflow Summary - ${data.project_name}

## Project Number

${data.project_number}

## Folder Name

${data.folder_name}

## Automation Purpose

${data.problem_solved}

## Technical Stack

${data.tools_used}

## Workflow Design

${data.workflow_steps}

## Learning Outcome

${data.key_learning}
`
};
const cleanName = data.project_name
  .toLowerCase()
  .replace(/[^a-z0-9 ]/g, "")
  .replace(/\s+/g, "-");

data.folder_name = `${data.project_number}-${cleanName}`;
return [
  {
    json: {
      ...data,
      readme_file_name: "README.md",
      setup_file_name: "setup-guide.md",
      linkedin_file_name: "linkedin-post.md",
      summary_file_name: "workflow-summary.md",
      ...files
    }
  }
];

const workflow = $workflow;

return [
  {
    json: {
      workflow_json: JSON.stringify(workflow, null, 2)
    }
  }
];

const data = $node["Generate Portfolio Files"].json;

const projectRepoBase = "https://github.com/Srivastsav/n8n-portfolio/tree/main";
const projectUrl = `${projectRepoBase}/${data.folder_name}`;

const tools = (data.tools_used || "")
  .split(",")
  .map(tool => tool.trim())
  .filter(Boolean);

const chips = tools
  .map(tool => `            <span>${tool}</span>`)
  .join("\n");

const cardNumber = `CASE FILE ${String(data.project_number).padStart(2, "0")}`;

const projectCardHtml = `
        <!-- ${cardNumber} -->
        <a
          class="system-card"
          href="${projectUrl}"
          target="_blank"
          rel="noopener"
        >
          <div class="card-number">${cardNumber}</div>

          <h3>${data.project_name}</h3>

          <p class="case-problem">
            ${data.problem_solved}
          </p>

          <ul class="case-structure">
            <li><strong>Input:</strong> Structured project details captured through n8n</li>
            <li><strong>Process:</strong> Dynamic documentation generation using workflow logic</li>
            <li><strong>Routing:</strong> Project artifacts routed into GitHub repository folders</li>
            <li><strong>Validation:</strong> File structure, Markdown output, and workflow JSON checked before publishing</li>
            <li><strong>Output:</strong> README, setup guide, workflow summary, LinkedIn draft, and workflow export</li>
          </ul>

          <p class="case-impact">
            ${data.key_learning}
          </p>

          <p class="case-failure">
            Failure insight: repeated project work should become a reusable publishing system, not manual copy-paste.
          </p>

          <div class="chips">
${chips}
          </div>
        </a>
`;

return [
  {
    json: {
      ...data,
      project_url: projectUrl,
      website_project_card_html: projectCardHtml
    }
  }
];

// Get the generated project card HTML from the previous Code node.
const websiteCard = $node["Generate Website Project Card"].json.website_project_card_html;

// Read GitHub file content.
let indexContent = $json.content || "";

// Decode GitHub base64 content into readable HTML.
if ($json.encoding === "base64" && $json.content) {
  indexContent = Buffer.from($json.content, "base64").toString("utf8");
}

// Stop if content is empty.
if (!indexContent || typeof indexContent !== "string") {
  throw new Error("Could not read index.html content from GitHub node output.");
}

// Preferred marker.
const startMarker = "<!-- PROJECTS_START -->";

// Backup insertion point from your existing website.
const caseOneMarker = "<!-- CASE 01 -->";

let updatedIndex = "";

// Best case: marker exists, insert card after it.
if (indexContent.includes(startMarker)) {
  updatedIndex = indexContent.replace(
    startMarker,
    `${startMarker}\n${websiteCard}`
  );
}

// Backup case: marker missing, insert card before CASE 01.
else if (indexContent.includes(caseOneMarker)) {
  updatedIndex = indexContent.replace(
    caseOneMarker,
    `<!-- PROJECTS_START -->\n${websiteCard}\n\n        ${caseOneMarker}`
  );
}

// If both are missing, stop with useful error.
else {
  throw new Error("Neither PROJECTS_START nor CASE 01 marker was found in index.html.");
}

// Create branch name for future PR step.
// Create a clean branch name using project name + timestamp
// Example: portfolio-update-01-n8n-portfolio-publisher-1777744000000
const cleanProjectName = $node["Generate Website Project Card"].json.project_name
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, "-")
  .replace(/^-|-$/g, "");

const branchName = `portfolio-update-${$node["Generate Website Project Card"].json.project_number}-${cleanProjectName}-${Date.now()}`;

// Create commit message for future GitHub update.
const commitMessage = `Add ${$node["Generate Website Project Card"].json.project_name} to portfolio website`;

// Return updated HTML and useful metadata.
return [
  {
    json: {
      updated_index_html: updatedIndex,
      original_sha: $json.sha,
      branch_name: branchName,
      commit_message: commitMessage
    }
  }
];

// Get updated HTML and metadata from the previous node
const data = $node["Insert Project Card into Website"].json;

// Convert updated index.html content into base64
// GitHub API requires file content to be sent as base64
const encodedContent = Buffer
  .from(data.updated_index_html, "utf8")
  .toString("base64");

// Clean branch name in case n8n or a copied expression added "=" accidentally
const cleanBranch = String(data.branch_name)
  .replace(/^=/, "")
  .trim();

// Return a clean payload for the HTTP Request node
return [
  {
    json: {
      message: data.commit_message,
      content: encodedContent,
      sha: data.original_sha,
      branch: cleanBranch
    }
  }
];

// Get the new branch name created earlier
const branchName = $node["Insert Project Card into Website"].json.branch_name;

// GitHub returns main branch commit SHA under object.sha
const mainBranchSha = $json.object.sha;

// Build the payload GitHub needs to create a new branch
return [
  {
    json: {
      ref: `refs/heads/${branchName}`,
      sha: mainBranchSha,
      branch: branchName
    }
  }
];
